"use strict";(self.webpackChunkcatalog_docs=self.webpackChunkcatalog_docs||[]).push([[53],{1109:t=>{t.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Catalog Overview","href":"/","docId":"intro"},{"type":"category","label":"Catalog Accounts","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/catalog-accounts/introduction","docId":"catalog-accounts/introduction"},{"type":"link","label":"Relayer","href":"/catalog-accounts/relayer","docId":"catalog-accounts/relayer"},{"type":"category","label":"Instant Account","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/catalog-accounts/instant-wallet/introduction","docId":"catalog-accounts/instant-wallet/introduction"},{"type":"link","label":"Guardian","href":"/catalog-accounts/instant-wallet/guardian","docId":"catalog-accounts/instant-wallet/guardian"},{"type":"link","label":"Insurance","href":"/catalog-accounts/instant-wallet/insurance","docId":"catalog-accounts/instant-wallet/insurance"},{"type":"link","label":"API","href":"/catalog-accounts/instant-wallet/api","docId":"catalog-accounts/instant-wallet/api"}]}]},{"type":"category","label":"Catalog Swaps","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/catalog-swaps/introduction","docId":"catalog-swaps/introduction"},{"type":"link","label":"HTLCs","href":"/catalog-swaps/htlcs","docId":"catalog-swaps/htlcs"},{"type":"link","label":"Resolvers","href":"/catalog-swaps/resolvers","docId":"catalog-swaps/resolvers"}]},{"type":"category","label":"Catalog Wallet","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/catalog-wallet/introduction","docId":"catalog-wallet/introduction"},{"type":"link","label":"SDK","href":"/catalog-wallet/sdk","docId":"catalog-wallet/sdk"}]}]},"docs":{"catalog-accounts/instant-wallet/api":{"id":"catalog-accounts/instant-wallet/api","title":"API","description":"Description","sidebar":"tutorialSidebar"},"catalog-accounts/instant-wallet/guardian":{"id":"catalog-accounts/instant-wallet/guardian","title":"Guardian","description":"The Guardian is a co-signing service for the Instant Account. The Guardian ensures secure transactions by eliminating the possibility of double spending without the need for confirmation delays. It achieves this by providing a second signature for all account operations, meaning it can guarantee no operation will be able to override existing ones. The Guardian does not require any trust from the user as it signs a refund transaction prior to any funding request, meaning the user can withdraw at any point in the event the Guardian becomes unresponsive.","sidebar":"tutorialSidebar"},"catalog-accounts/instant-wallet/insurance":{"id":"catalog-accounts/instant-wallet/insurance","title":"Insurance","description":"Catalog implements an insurance contract in the event a user fails to receive their funds after the Guardian provides its guarantee. The contract uses an oracle to check for proof-of-exclusion, which alongside the Guardian\u2019s signed commitment, enables the user to redeem an equivalent amount of funds from the insurance pool.","sidebar":"tutorialSidebar"},"catalog-accounts/instant-wallet/introduction":{"id":"catalog-accounts/instant-wallet/introduction","title":"Introduction","description":"All Catalog Accounts come with the ability to open an Instant Account. An Instant Account is a special type of wallet which enables instant transfers and cross-chain swaps, without requiring any form of trust. It does this through a 2-of-2 multi-sig requirement with the Guardian component, which allows users to bypass confirmation delays.","sidebar":"tutorialSidebar"},"catalog-accounts/introduction":{"id":"catalog-accounts/introduction","title":"Introduction","description":"Catalog Accounts support the way you interact with Web3. These are non-custodial accounts that allow you to store assets from any blockchain, and use them without waiting for confirmation delays.","sidebar":"tutorialSidebar"},"catalog-accounts/relayer":{"id":"catalog-accounts/relayer","title":"Relayer","description":"Work in progress.","sidebar":"tutorialSidebar"},"catalog-swaps/htlcs":{"id":"catalog-swaps/htlcs","title":"HTLCs","description":"Catalog Swaps use hashed timelock contracts (HTLCs) for execution, which function as a two-way virtual safe.","sidebar":"tutorialSidebar"},"catalog-swaps/introduction":{"id":"catalog-swaps/introduction","title":"Introduction","description":"Catalog Swaps offer you a way to execute cross-chain swaps instantly and seamlessly. Multiple Resolvers compete in an auction format to provide the best possible rate for the user, allowing gas payments in any token. Atomic execution for Catalog Swaps is guaranteed through the use of HTLCs.","sidebar":"tutorialSidebar"},"catalog-swaps/resolvers":{"id":"catalog-swaps/resolvers","title":"Resolvers","description":"Work in progress.","sidebar":"tutorialSidebar"},"catalog-wallet/introduction":{"id":"catalog-wallet/introduction","title":"Introduction","description":"Catalog Wallet is a browser extension that enables seamless support for cross-chain assets on all dApps, meaning you can transact Bitcoin and other assets directly on your favorite exchange or NFT marketplace. Catalog Wallet uses Catalog Accounts under the hood, abstracting away all of the powerful technology that make your multichain experience possible.","sidebar":"tutorialSidebar"},"catalog-wallet/sdk":{"id":"catalog-wallet/sdk","title":"SDK","description":"Work in progress.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Catalog Overview","description":"What is Catalog?","sidebar":"tutorialSidebar"}}}')}}]);